from functools import lru_cache
from collections import Counter, defaultdict
from itertools import combinations, permutations

def qpoly_add(a,b):
    c=Counter(a)
    for k,v in b.items(): c[k]+=v
    return +c
def qpoly_shift(a,s,coef=1):
    return Counter({k+s:v*coef for k,v in a.items()})
def qpoly_mul_by_qint(a,k): # [k]_q = 1...q^{k-1}
    c=Counter()
    for e,v in a.items():
        for s in range(k):
            c[e+s]+=v
    return +c

def F_rec(nmax):
    F={(0,0):Counter({0:1})}
    for r in range(1,nmax+1):
        for k in range(1,r+1):
            c=Counter()
            if (r-1,k-1) in F:
                c+=qpoly_mul_by_qint(F[(r-1,k-1)],k)
            if (r-1,k) in F:
                c+=qpoly_mul_by_qint(F[(r-1,k)],k)
            F[(r,k)]=+c
    return F

def ordered_partitions(n,k):
    # generate all ordered set partitions of [1..n] into k blocks
    # assign surjection f from elements to block labels 0..k-1, all used; blocks sorted naturally
    # for small n
    import itertools
    for labels in itertools.product(range(k), repeat=n):
        if set(labels)==set(range(k)):
            blocks=[set() for _ in range(k)]
            for i,l in enumerate(labels, start=1):
                blocks[l].add(i)
            yield tuple(tuple(sorted(b)) for b in blocks)

def inv_op(blocks):
    inv=0
    k=len(blocks)
    # pair (i,j) i<j, i=min B_m, j in B_l, l<m
    for m,Bm in enumerate(blocks):
        i=min(Bm)
        for l in range(m):
            for j in blocks[l]:
                if i<j:
                    inv+=1
    return inv

for n in range(1,6):
    F=F_rec(n)
    for k in range(1,n+1):
        enum=Counter()
        for op in ordered_partitions(n,k):
            enum[inv_op(op)]+=1
        if F[(n,k)] != enum:
            print("mismatch", n,k,F[(n,k)],enum)
            raise SystemExit
print("all match")

def poly2d_H(n):
    # return Counter (qexp,zexp)->coeff H
    F=F_rec(n)
    C=Counter()
    for k in range(1,n+1):
        z=n-k
        for qe,coef in F[(n,k)].items():
            C[(qe,z)]+=coef
    return C

def G_from_H_div(n):
    # compute G such that (q+z)G=H-1 by recurrence formula
    F=F_rec(n)
    G=Counter()
    for r in range(1,n):
        for k in range(1,r+1):
            z=r-k
            for qe,coef in qpoly_mul_by_qint(F[(r,k)], k).items():
                G[(qe,z)]+=coef
    return +G

def multiply_q_plus_z(G):
    C=Counter()
    for (qe,ze),coef in G.items():
        C[(qe+1,ze)]+=coef
        C[(qe,ze+1)]+=coef
    return +C

for n in range(1,7):
    H=poly2d_H(n)
    Hminus=Counter(H)
    Hminus[(0,0)]-=1
    Hminus=+Hminus
    G=G_from_H_div(n)
    assert multiply_q_plus_z(G)==Hminus, (n, multiply_q_plus_z(G), Hminus)
print("division recurrence checks")

def G_enum_theorem(n):
    G=Counter()
    for r in range(2,n+1):
        for k in range(1,r):
            z=r-k-1
            for op in ordered_partitions(r,k):
                # r not singleton block
                if any(len(B)==1 and B[0]==r for B in op):
                    continue
                G[(inv_op(op),z)]+=1
    return +G

for n in range(1,6):
    assert G_enum_theorem(n)==G_from_H_div(n), (n,G_enum_theorem(n), G_from_H_div(n))
